## 2. PAGE TRANSITION MODULE — `/shared/transitions.js`

**Full specification:**

```javascript
/**
 * AlphaClaw Apex Page Transition System
 * Import: import { navTo, initTransitions } from '/shared/transitions.js';
 *
 * Usage:
 *   initTransitions();  // Call once on page load — creates overlay DOM + handles direct-load fade-in
 *   navTo('/chat/', '💬', 'Council Chat');  // Navigate with transition
 */

// Page config: path prefix → { icon, label }
const PAGE_CONFIG = {
  '/dashboard/':     { icon: '⬡',  label: 'Dashboard' },
  '/chat/':          { icon: '💬', label: 'Council Chat' },
  '/roundtable/':    { icon: '🔮', label: 'Roundtable' },
  '/vault/':         { icon: '🔐', label: 'Vault' },
  '/knowledge/':     { icon: '📚', label: 'Knowledge' },
  '/mission/':       { icon: '📡', label: 'Mission Control' },
  '/monitor/':       { icon: '📊', label: 'Monitor' },
  '/analytics/':     { icon: '📈', label: 'Analytics' },
  '/tasks/':         { icon: '✅', label: 'Tasks' },
  '/files/':         { icon: '📁', label: 'Files' },
  '/leads/':         { icon: '🎯', label: 'Leads' },
  '/icat/':          { icon: '🐱', label: 'ICat' },
  '/pipeline/':      { icon: '🔄', label: 'Pipeline' },
  '/broadcast/':     { icon: '📢', label: 'Broadcast' },
  '/settings/':      { icon: '⚙️', label: 'Settings' },
  '/reports/':       { icon: '📋', label: 'Reports' },
  '/notifications/': { icon: '🔔', label: 'Notifications' },
  '/login/':         { icon: '🔑', label: 'Login' },
};

let overlay = null;
let isTransitioning = false;

/**
 * Create overlay DOM element (called once)
 */
function createOverlay() {
  if (document.getElementById('apex-transition-overlay')) {
    overlay = document.getElementById('apex-transition-overlay');
    return;
  }
  overlay = document.createElement('div');
  overlay.id = 'apex-transition-overlay';
  overlay.innerHTML = `
    <div class="transition-icon"></div>
    <div class="transition-label"></div>
  `;
  document.body.appendChild(overlay);
}

/**
 * Initialize transitions on page load.
 * - Creates overlay
 * - Fades in current page content (direct-load fallback)
 */
export function initTransitions() {
  createOverlay();

  // Direct-load: fade in the page content with stagger
  requestAnimationFrame(() => {
    const main = document.querySelector('.page-main, .page-content, .app, .main, .page, .dash-content');
    if (main) {
      main.classList.add('page-enter');
      requestAnimationFrame(() => main.classList.add('visible'));
    }

    // Auto-stagger any .stagger-item children
    document.querySelectorAll('.stagger-item').forEach((el, i) => {
      el.style.animationDelay = `${i * 50}ms`;
    });
  });
}

/**
 * Navigate to a new page with cinematic transition.
 * @param {string} path - Target URL path
 * @param {string} icon - Emoji icon for transition screen
 * @param {string} label - Text label for transition screen
 */
export function navTo(path, icon, label) {
  if (isTransitioning) return;
  if (window.location.pathname === path) return;
  isTransitioning = true;

  // Look up config if icon/label not provided
  if (!icon || !label) {
    const config = PAGE_CONFIG[path] || { icon: '✦', label: 'MAGI' };
    icon = icon || config.icon;
    label = label || config.label;
  }

  const iconEl = overlay.querySelector('.transition-icon');
  const labelEl = overlay.querySelector('.transition-label');
  iconEl.textContent = icon;
  labelEl.textContent = label;

  // Step 1: Fade out current content (200ms)
  const main = document.querySelector('.page-main, .page-content, .app, .main, .page, .dash-content');
  if (main) {
    main.style.transition = 'opacity 0.2s ease';
    main.style.opacity = '0';
  }

  // Step 2: Show overlay (200ms after content starts fading)
  setTimeout(() => {
    overlay.classList.add('active');

    // Step 3: Show icon (200ms after overlay appears)
    setTimeout(() => {
      overlay.classList.add('show-icon');

      // Step 4: Show label (500ms after icon)
      setTimeout(() => {
        overlay.classList.add('show-label');

        // Step 5: Hold for 1 second, then navigate
        setTimeout(() => {
          window.location.href = path;
        }, 1000);
      }, 500);
    }, 200);
  }, 200);
}

/**
 * Cleanup — call if page stays loaded (SPA-like)
 */
export function cleanupTransition() {
  if (!overlay) return;
  overlay.classList.remove('active', 'show-icon', 'show-label');
  isTransitioning = false;
}

export { PAGE_CONFIG };
```

### Integration with nav.js:
In `nav.js`, change link clicks from direct `href` navigation to calling `navTo()`:

```javascript
// BEFORE:
html += `<a class="magi-nav-item${isActive}" href="${item.path}">`;

// AFTER:
html += `<a class="magi-nav-item${isActive}" href="${item.path}" data-nav-path="${item.path}" data-nav-icon="${item.icon}" data-nav-label="${item.label}">`;
```

Then add a click interceptor at the bottom of `renderNav()`:

```javascript
// Intercept nav clicks for transitions
nav.addEventListener('click', (e) => {
  const link = e.target.closest('.magi-nav-item');
  if (!link) return;
  e.preventDefault();
  const path = link.dataset.navPath;
  const icon = link.dataset.navIcon;
  const label = link.dataset.navLabel;
  if (path && window.location.pathname !== path) {
    navTo(path, icon, label);
  }
});
```

### Fallback for Direct URL Access:
When a user navigates directly (bookmark, URL bar), there's no transition. Instead, `initTransitions()` applies a simple fade-in from bottom animation on the main content container. This is handled by the `page-enter` + `visible` class system in `initTransitions()`.

