## 5. STAGGERED ENTRY ANIMATION SPEC

### CSS (already in core.css above):
The `.stagger-item` class and its nth-child delays are defined in core.css (see Section 1).

### JS Module — Add to `core.js`:

```javascript
// ─── Stagger Animation ────────────────────────────

/**
 * Apply stagger animation to child elements.
 * @param {string} parentSelector - CSS selector for the container
 * @param {string} childSelector - CSS selector for children (default: '> *')
 * @param {number} delayMs - Delay between items in ms (default: 50)
 */
export function staggerIn(parentSelector, childSelector = '> *', delayMs = 50) {
  const parent = document.querySelector(parentSelector);
  if (!parent) return;
  const children = parent.querySelectorAll(childSelector);
  children.forEach((child, i) => {
    child.style.opacity = '0';
    child.style.transform = 'translateY(12px)';
    child.style.transition = `opacity 0.4s var(--ease-out), transform 0.4s var(--ease-out)`;
    child.style.transitionDelay = `${i * delayMs}ms`;
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        child.style.opacity = '1';
        child.style.transform = 'translateY(0)';
      });
    });
  });
}

/**
 * Alternative: just add the class and let CSS handle it.
 * Requires children to NOT have stagger-item class initially.
 */
export function addStaggerClass(parentSelector, childSelector = '> *') {
  const parent = document.querySelector(parentSelector);
  if (!parent) return;
  parent.querySelectorAll(childSelector).forEach((child) => {
    child.classList.add('stagger-item');
  });
}
```

### Usage in Pages:

```javascript
