import { staggerIn } from '/shared/core.js';

// After rendering cards/items:
staggerIn('.summary', '.card');      // Stagger stat cards
staggerIn('.apps', '.app-link');     // Stagger dashboard app links
staggerIn('.agent-grid', '.agent-card'); // Stagger agent cards
