## 6. COUNT-UP ANIMATION FOR STATS

### Add to `/shared/core.js`:

```javascript
// ─── Count-Up Animation ───────────────────────────

/**
 * Animate a number from 0 to target.
 * @param {HTMLElement} el - Element containing the number
 * @param {number} target - Final number
 * @param {number} duration - Animation duration in ms (default: auto based on magnitude)
 * @param {string} prefix - Text before number (e.g., '$')
 * @param {string} suffix - Text after number (e.g., '%')
 */
export function countUp(el, target, duration, prefix = '', suffix = '') {
  if (!el) return;

  // Auto-duration: 800ms base + 200ms per digit, max 2000ms
  if (!duration) {
    const digits = Math.max(1, Math.floor(Math.log10(Math.abs(target || 1)) + 1));
    duration = Math.min(800 + digits * 200, 2000);
  }

  const startTime = performance.now();
  const isFloat = !Number.isInteger(target);
  const decimals = isFloat ? (target.toString().split('.')[1] || '').length : 0;

  function easeOutQuart(t) {
    return 1 - Math.pow(1 - t, 4);
  }

  function update(now) {
    const elapsed = now - startTime;
    const progress = Math.min(elapsed / duration, 1);
    const easedProgress = easeOutQuart(progress);
    const current = target * easedProgress;

    if (isFloat) {
      el.textContent = `${prefix}${current.toFixed(decimals)}${suffix}`;
    } else {
      el.textContent = `${prefix}${Math.round(current).toLocaleString()}${suffix}`;
    }

    if (progress < 1) {
      requestAnimationFrame(update);
    } else {
      // Final exact value
      el.textContent = `${prefix}${isFloat ? target.toFixed(decimals) : target.toLocaleString()}${suffix}`;
    }
  }

  requestAnimationFrame(update);
}

/**
 * Auto-init count-up for elements with data-count-target attribute.
 * Uses IntersectionObserver to trigger on scroll-into-view.
 *
 * HTML: <span class="count-up" data-count-target="1234" data-count-prefix="$">0</span>
 */
export function initCountUp() {
  const elements = document.querySelectorAll('.count-up[data-count-target]');
  if (!elements.length) return;

  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting && !entry.target.dataset.counted) {
        entry.target.dataset.counted = 'true';
        const target = parseFloat(entry.target.dataset.countTarget);
        const prefix = entry.target.dataset.countPrefix || '';
        const suffix = entry.target.dataset.countSuffix || '';
        const duration = entry.target.dataset.countDuration
          ? parseInt(entry.target.dataset.countDuration)
          : undefined;
        countUp(entry.target, target, duration, prefix, suffix);
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.3 });

  elements.forEach((el) => observer.observe(el));
}
```

